    path and returns a transformed path. If given, it is applied
    to the requested template name before the lookup is delegated
    to the child loaders. Errors raised while resolving the
    transformed path are reported using the original,
    untransformed name.
"""

def __init__(
    self,
    loaders: t.Sequence[BaseLoader],
